const data = $input.all()[0].json;
const rates = data.rates || {};
const today = new Date().toISOString().split('T')[0];
const currencies = ['USD','GBP','EUR','CHF','CAD','AUD','CNY','ZAR'];
const results = [];

for (const ccy of currencies) {
  if (rates[ccy]) {
    // API gives NGN per 1 unit of each CCY
    // open.er-api gives: 1 NGN = X CCY, so rate_to_ngn = 1 / rates[ccy]
    const rate_to_ngn = rates[ccy] > 0 ? parseFloat((1 / rates[ccy]).toFixed(4)) : 0;
    results.push({ json: { currency_code: ccy, rate_to_ngn, rate_date: today, source: 'open.er-api.com' } });
  }
}

return results.length > 0 ? results : [{ json: { error: 'No rates found', raw: data } }];

